// Helper: given (modId, sessionN), return the array of JAMA Nutrition
// competency objects this session is tagged with (or empty array).
// Joins the THREAD-NUTR session sub field ("Theme: …, #14, #28") against
// window.JAMA_NUTR_COMPETENCIES.
window.jamaForSession = function jamaForSession(modId, sessionN) {
  const threads = window.CANONICAL_THREADS || [];
  const JAMA = window.JAMA_NUTR_COMPETENCIES || {};
  const nutr = threads.find(t => t && t.id === "nutr");
  if (!nutr) return [];
  const tag = (nutr.sessions || []).find(s => s.modId === modId && Number(s.n) === Number(sessionN));
  if (!tag || !tag.sub) return [];
  const out = [];
  const seen = new Set();
  for (const m of tag.sub.matchAll(/#\s*(\d+)/g)) {
    const n = parseInt(m[1], 10);
    if (seen.has(n)) continue;
    seen.add(n);
    const c = JAMA[String(n)];
    if (c) out.push(c);
  }
  return out;
};

// Helper: parse "Theme: X" out of the nutr sub field.
window.jamaThemeForSession = function jamaThemeForSession(modId, sessionN) {
  const threads = window.CANONICAL_THREADS || [];
  const nutr = threads.find(t => t && t.id === "nutr");
  if (!nutr) return "";
  const tag = (nutr.sessions || []).find(s => s.modId === modId && Number(s.n) === Number(sessionN));
  if (!tag || !tag.sub) return "";
  const m = tag.sub.match(/Theme:\s*([^,;\n]+)/i);
  return m ? m[1].trim() : "";
};
